class Heap {
    constructor(cmp) { this.a = []; this.cmp = cmp; }
    size() { return this.a.length; }
    peek() { return this.a[0]; }
    push(x) {
        const a = this.a; a.push(x); let i = a.length - 1;
        while (i > 0) { const p = (i - 1) >> 1; if (this.cmp(a[i], a[p]) < 0) { [a[i], a[p]] = [a[p], a[i]]; i = p; } else break; }
    }
    pop() {
        const a = this.a; const top = a[0]; const last = a.pop();
        if (a.length) { a[0] = last; let i = 0; const n = a.length;
            while (true) { let l = 2*i+1, r = 2*i+2, s = i;
                if (l < n && this.cmp(a[l], a[s]) < 0) s = l;
                if (r < n && this.cmp(a[r], a[s]) < 0) s = r;
                if (s === i) break; [a[i], a[s]] = [a[s], a[i]]; i = s; } }
        return top;
    }
}
var assignTasks = function(servers, tasks) {
    const free = new Heap((x, y) => x[0] !== y[0] ? x[0] - y[0] : x[1] - y[1]);
    for (let i = 0; i < servers.length; i++) free.push([servers[i], i]);
    const busy = new Heap((x, y) => x[0] !== y[0] ? x[0] - y[0] : (x[1] !== y[1] ? x[1] - y[1] : x[2] - y[2]));
    const ans = [];
    let t = 0;
    for (let j = 0; j < tasks.length; j++) {
        t = Math.max(t, j);
        while (busy.size() && busy.peek()[0] <= t) {
            const [ft, w, idx] = busy.pop();
            free.push([w, idx]);
        }
        if (!free.size()) {
            t = busy.peek()[0];
            while (busy.size() && busy.peek()[0] <= t) {
                const [ft, w, idx] = busy.pop();
                free.push([w, idx]);
            }
        }
        const [w, idx] = free.pop();
        ans.push(idx);
        busy.push([t + tasks[j], w, idx]);
    }
    return ans;
};
